import{_ as e}from"./_plugin-vue_export-helper-c27b6911.js";import{o as t,j as a,x as s}from"./app-7ad23691.js";const o={},c={class:"return-policy-page"},i=s('<div class="page-header text-center mb-12" data-v-a4d5cc49><h1 class="text-h3 font-weight-bold mb-0" data-v-a4d5cc49>KIDAN RETURN &amp; REFUND POLICY</h1></div><div class="policy-content" data-v-a4d5cc49><div class="intro-section mb-10" data-v-a4d5cc49><p class="text-body-1" style="line-height:1.8;color:#555;" data-v-a4d5cc49> At KIDAN, we pride ourselves on curating and delivering only the finest African-made and Global fashion and lifestyle pieces. However, we understand that sometimes a purchase may not meet your expectations. </p></div><div class="section mb-8" data-v-a4d5cc49><h2 class="text-h5 font-weight-bold mb-4" data-v-a4d5cc49>Eligibility for Return</h2><p class="text-body-1" style="line-height:1.8;color:#555;" data-v-a4d5cc49> You may request a return or exchange within 7 days of receiving your order To qualify, items must be: Unused and unworn In original packaging with all tags, boxes, and dust bags attached Free from stains, damage, or scent Not part of our non-returnable categories (beauty, fragrances, intimates, custom items) The item is not a final sale, custom-made, or intimate product (such as jewellery, underwear, or beauty items). Proof of purchase (order number or receipt) is provided. </p></div><div class="section mb-8" data-v-a4d5cc49><h2 class="text-h5 font-weight-bold mb-4" data-v-a4d5cc49>Return Process</h2><p class="text-body-1" style="line-height:1.8;color:#555;" data-v-a4d5cc49> Submit a return request via the return page or the official email of the company within 7 days of delivery. Our customer care team will review and provide return approval and address details. Ship the item(s) back to us in secure packaging. Please note that return shipping costs are the responsibility of the customer, unless the return is due to our error or a defective product. Once your return is approved, you can either: Drop it off at a KIDAN Delivery Point, or Request a pickup (available in select cities) Refunds are processed within 3–7 working days after the item is inspected. </p></div><div class="section mb-8" data-v-a4d5cc49><h2 class="text-h5 font-weight-bold mb-4" data-v-a4d5cc49>Exchanges</h2><p class="text-body-1" style="line-height:1.8;color:#555;" data-v-a4d5cc49> If you need a different size, colour, or product, you can request an exchange during the return process. This follows the same steps as the refund policy. </p></div><div class="section mb-10" data-v-a4d5cc49><h2 class="text-h5 font-weight-bold mb-4" data-v-a4d5cc49>Non-Returnable Items</h2><p class="text-body-1" style="line-height:1.8;color:#555;" data-v-a4d5cc49> For hygiene and safety reasons, the following cannot be returned: Beauty products, fragrances, skincare, intimates, swimwear, and discounted &quot;final sale&quot; items. </p></div><div class="contact-section" data-v-a4d5cc49><p class="text-body-1 mb-2" style="line-height:1.8;color:#555;" data-v-a4d5cc49> For questions: Via WhatsApp: +234707827096 </p><p class="text-body-1 mb-2" style="line-height:1.8;color:#555;" data-v-a4d5cc49> Email: support@kidanstore.com </p><p class="text-body-1 mb-0" style="line-height:1.8;color:#555;" data-v-a4d5cc49> Social media: Kidanglobal </p></div></div>',2),r=[i];function d(n,l){return t(),a("div",c,r)}const p=e(o,[["render",d],["__scopeId","data-v-a4d5cc49"]]);export{p as default};
